// Explode a lista de ciclos em 1 item por ciclo e monta o corpo da chamada ao Claude.
const SYSTEM = "Você é um analista de vendas de farmácia. Recebe a transcrição de UMA conversa de WhatsApp entre a farmácia e um cliente e classifica o desfecho. Responda APENAS com um objeto JSON (sem markdown, sem texto fora do JSON) com as chaves: isSale (boolean: a conversa resultou em venda concluída), saleValueCents (inteiro em centavos de BRL do valor estimado da venda, ou null se não houver/indefinido), stage (string curta do estágio, ex.: 'Cotação', 'Negociação', 'Venda fechada', 'Perdida', ou null), lossReason (string curta do motivo de não-venda, ou null quando isSale=true), summary (resumo em pt-BR, 1 a 3 frases), confidence (número de 0 a 1 com sua confiança). Não invente valores: se o preço não aparece, use null.";
const MODEL = "claude-haiku-4-5-20251001";
const data = $input.first().json;
const cycles = Array.isArray(data.cycles) ? data.cycles : [];
return cycles.map((c) => {
  const transcript = (c.messages || [])
    .map((m) => (m.direction === 'INBOUND' ? 'Cliente' : 'Farmácia') + ': ' + m.text)
    .join('\n');
  const userContent = 'Conversa com o contato "' + c.contactName + '":\n\n' + transcript + '\n\nResponda só com o JSON.';
  return {
    json: {
      cycleId: c.cycleId,
      pharmacyId: c.pharmacyId,
      lastMessageAt: c.lastMessageAt,
      model: MODEL,
      body: {
        model: MODEL,
        max_tokens: 500,
        system: SYSTEM,
        messages: [{ role: 'user', content: userContent }],
      },
    },
  };
});

// Junta cada resposta do Claude com o meta do ciclo e monta o lote.
// Robustez:
//  (1) length-guard: se algum item caiu (desalinhou resposta x meta), aborta o tick
//      inteiro em vez de gravar analise no ciclo ERRADO. Ciclos ficam pending e re-tentam.
//  (2) parse-fail: PULA o ciclo (nao grava) -> continua pending e re-tenta no proximo tick,
//      em vez de gravar 'analise-lixo' que tirava o ciclo da fila pra sempre.
const responses = $input.all();
const metas = $('Preparar ciclos').all();
if (responses.length !== metas.length) {
  throw new Error('desalinhamento respostas/metas (' + responses.length + ' vs ' + metas.length + ') - abortando para nao corromper ciclos');
}
const results = [];
for (let i = 0; i < responses.length; i++) {
  const meta = metas[i].json;
  let text = '';
  try { text = responses[i].json.content[0].text; } catch (e) {}
  let p;
  try { p = JSON.parse(String(text).replace(/```json/gi, '').replace(/```/g, '').trim()); }
  catch (e) { continue; } // parse falhou -> nao grava; ciclo continua pending
  const value = (Number.isFinite(p.saleValueCents) && p.saleValueCents >= 0) ? Math.round(p.saleValueCents) : null;
  const summary = (String(p.summary || '').trim() || 'Sem resumo.').slice(0, 4000);
  results.push({
    cycleId: meta.cycleId,
    pharmacyId: meta.pharmacyId,
    isSale: p.isSale === true,
    saleValueCents: value,
    stage: p.stage != null ? String(p.stage) : null,
    lossReason: p.lossReason != null ? String(p.lossReason) : null,
    summary,
    confidence: (typeof p.confidence === 'number' && p.confidence >= 0 && p.confidence <= 1) ? p.confidence : 0,
    model: meta.model,
    analyzedThroughMessageAt: meta.lastMessageAt,
  });
}
// nada valido -> retorna [] e o POST nao dispara (evita 422 com results vazio).
return results.length ? [{ json: { results } }] : [];
